196	/// Extract the ochid trailer value from a commit description, if present.
197	pub fn extract_ochid(commit: &Commit) -> Option<String> {
198	    for line in commit.description().lines().rev() {
199	        let trimmed = line.trim();
200	        if let Some(value) = trimmed.strip_prefix("ochid:") {
201	            return Some(value.trim().to_string());
202	        }
203	    }
204	    None
205	}
206	
207	/// Format: changeID ochid(padded) first-line (single line).
208	///
209	/// ochid column is left-padded to `width` characters. If no ochid, a blank
210	/// placeholder of that width is used.
211	pub fn format_commit_with_ochid(commit: &Commit, width: usize) -> String {
212	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
213	    let change_short = &change_hex[..change_hex.len().min(12)];
214	    let ochid = extract_ochid(commit).unwrap_or_default();
215	    let first_line = commit.description().lines().next().unwrap_or("");
216	    let title = if first_line.is_empty() {
217	        "(no description set)"
218	    } else {
219	        first_line
220	    };
221	    format!("{change_short}  {ochid:<width$}  {title}")
222	}
223	
224	/// Format: just the short changeID.
225	pub fn format_chid(commit: &Commit) -> String {
226	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
227	    change_hex[..change_hex.len().min(12)].to_string()
228	}
229	
230	/// Format: changeID commitID first-line (single line).
231	pub fn format_commit_short(commit: &Commit) -> String {
232	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
233	    let change_short = &change_hex[..change_hex.len().min(12)];
234	    let commit_hex = commit.id().hex();
235	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
236	    let first_line = commit.description().lines().next().unwrap_or("");
237	    if first_line.is_empty() {
238	        format!("{change_short} {commit_short} (no description set)")
239	    } else {
240	        format!("{change_short} {commit_short} {first_line}")
241	    }
242	}
243	
244	/// Format: changeID commitID first-line, then remaining description lines.
245	pub fn format_commit_full(commit: &Commit) -> String {
246	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
247	    let change_short = &change_hex[..change_hex.len().min(12)];
248	    let commit_hex = commit.id().hex();
249	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
250	    let desc = commit.description();
251	    if desc.is_empty() {
252	        format!("{change_short} {commit_short} (no description set)")
253	    } else {
254	        let mut lines = desc.lines();
255	        let first_line = lines.next().unwrap_or("");
256	        let mut result = format!("{change_short} {commit_short} {first_line}");
257	        for line in lines {
258	            result.push('\n');
259	            result.push_str(line);
260	        }
261	        result
262	    }
263	}
264	
265	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
266	///
267	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
268	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
269	/// and the index of the anchor commit within the list.
270	///
271	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
272	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
273	pub fn collect_ids(
274	    workspace: &Workspace,
275	    repo: &Arc<ReadonlyRepo>,
276	    rev: &str,
277	    desc_count: Option<usize>,
278	    anc_count: Option<usize>,
279	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
280	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
281	    if anchor_ids.is_empty() {
282	        return Err(format!("no commit found for revision '{rev}'").into());
283	    }
284	    let anchor_id = &anchor_ids[0];
285	    let root_commit_id = repo.store().root_commit_id().clone();
286	
287	    // Descendants (closest to anchor)
288	    let mut desc_ids: Vec<CommitId> = Vec::new();
289	    if desc_count != Some(0) {
290	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
291	        desc_ids = descendant_ids
292	            .into_iter()
293	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
294	            .collect();
295	        if let Some(n) = desc_count {
296	            let start = desc_ids.len().saturating_sub(n);
297	            desc_ids = desc_ids[start..].to_vec();
298	        }
299	    }
300	
301	    // Ancestors (closest to anchor)
302	    let mut anc_ids: Vec<CommitId> = Vec::new();
303	    if anc_count != Some(0) {
304	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
305	        let limit = anc_count.unwrap_or(usize::MAX);
306	        let mut count = 0;
307	        for commit_id in ancestor_ids {
308	            if commit_id == root_commit_id || commit_id == *anchor_id {
309	                continue;
310	            }
311	            anc_ids.push(commit_id);
312	            count += 1;
313	            if count >= limit {
314	                break;
315	            }
316	        }
317	    }
318	
319	    let anchor_index = desc_ids.len();
320	    let mut result = desc_ids;
321	    result.push(anchor_id.clone());
322	    result.extend(anc_ids);
323	    Ok((result, anchor_index))
324	}
