326	/// Header style between repos in multi-repo output.
327	#[derive(Debug, Clone)]
328	pub enum Header {
329	    /// Show `deco path deco` header per repo.
330	    Label(String),
331	    /// No header at all.
332	    None,
333	}
334	
335	/// Resolve `-l` / `-L` flags into a `Header`.
336	///
337	/// `-L` (no header) takes precedence over `-l` (label decoration).
338	pub fn resolve_header(label: &str, suppress: bool) -> Header {
339	    if suppress {
340	        Header::None
341	    } else {
342	        Header::Label(label.to_string())
343	    }
344	}
345	
346	/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
347	///
348	/// Header style controls output between repos.
349	/// Continues past errors, printing them to stderr, and returns an error if any failed.
350	pub fn for_each_repo<F>(
351	    raw_repos: &[PathBuf],
352	    header: &Header,
353	    mut body: F,
354	) -> Result<(), Box<dyn std::error::Error>>
355	where
356	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
357	{
358	    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
359	        vec![PathBuf::from(".")]
360	    } else {
361	        raw_repos
362	            .iter()
363	            .flat_map(|p| {
364	                p.to_string_lossy()
365	                    .split(',')
366	                    .map(|s| PathBuf::from(s.trim()))
367	                    .collect::<Vec<_>>()
368	            })
369	            .collect()
370	    };
371	    let multi = repos.len() > 1;
372	    let mut first = true;
373	    let mut errors: Vec<String> = Vec::new();
374	
375	    for repo_path in &repos {
376	        if multi {
377	            match header {
378	                Header::Label(deco) => {
379	                    if !first {
380	                        println!();
381	                    }
382	                    println!(
383	                        "{}",
384	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
385	                    );
386	                }
387	                Header::None => {}
388	            }
389	        }
390	        first = false;
391	
392	        match load_repo(repo_path) {
393	            Ok((workspace, repo)) => {
394	                if let Err(e) = body(&workspace, &repo) {
395	                    eprintln!("error ({}): {e}", repo_path.display());
396	                    errors.push(format!("{}: {e}", repo_path.display()));
397	                }
398	            }
399	            Err(e) => {
400	                eprintln!("error ({}): {e}", repo_path.display());
401	                errors.push(format!("{}: {e}", repo_path.display()));
402	            }
403	        }
404	    }
405	
406	    if errors.is_empty() {
407	        Ok(())
408	    } else {
409	        Err(format!("{} repo(s) had errors", errors.len()).into())
410	    }
411	}
