413	pub fn load_repo(
414	    path: &Path,
415	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
416	    let config = StackedConfig::with_defaults();
417	    let settings = UserSettings::from_config(config)?;
418	    let store_factories = StoreFactories::default();
419	    let working_copy_factories = default_working_copy_factories();
420	
421	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
422	    let repo = workspace.repo_loader().load_at_head().block_on()?;
423	
424	    Ok((workspace, repo))
425	}
