    fn parse_dot_rev_both() {
        let spec = parse_dot_rev("..@..");
        assert_eq!(spec.rev, "@");
        assert_eq!(spec.desc_count, None);
        assert_eq!(spec.anc_count, None);
    }

    #[test]
