use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::Stdio;

use clap::Args;

#[derive(Args, Debug)]
pub struct FinalizeArgs {
    /// Path to jj repo
    #[arg(long, default_value = ".")]
    pub repo: PathBuf,

    /// Source revision to squash
    #[arg(long, default_value = "@")]
    pub source: String,

    /// Target revision to squash into
    #[arg(long, default_value = "@-")]
    pub target: String,

    /// Seconds to wait before squashing
    #[arg(long, default_value_t = 10.0)]
    pub delay: f64,

    /// Bookmark to advance to target after squash (required)
    #[arg(long)]
    pub bookmark: String,

    /// Push after squashing
    #[arg(long)]
    pub push: bool,

    /// Log file path (default: /tmp/vc-x1-finalize-<timestamp-millis>.log)
    #[arg(long)]
    pub log: Option<PathBuf>,

    /// Detach and run in the background
    #[arg(long)]
    pub detach: bool,

    /// Internal: run exec path (used by detach)
    #[arg(long, hide = true)]
    pub exec: bool,
}

#[derive(Debug)]
pub struct FinalizeOpts {
    pub repo: PathBuf,
    pub source: String,
    pub target: String,
    pub bookmark: String,
    pub delay_secs: f64,
    pub push: bool,
    pub log: PathBuf,
    pub detach: bool,
    pub exec: bool,
}

impl FinalizeArgs {
    pub fn into_opts(self) -> FinalizeOpts {
        let log = self.log.unwrap_or_else(|| {
            PathBuf::from(format!(
                "/tmp/vc-x1-finalize-{}.log",
                std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_millis()
            ))
        });
        FinalizeOpts {
            repo: self.repo,
            source: self.source,
            target: self.target,
            bookmark: self.bookmark,
            delay_secs: self.delay,
            push: self.push,
            log,
            detach: self.detach,
            exec: self.exec,
        }
    }
}

pub fn log_msg(log: &Path, msg: &str) {
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let pid = std::process::id();
    let line = format!("[{nanos}] pid={pid} {msg}\n");
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(log)
    {
        let _ = f.write_all(line.as_bytes());
    }
}

fn run_jj(args: &[&str], log: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let args_str = args.join(" ");
    log_msg(log, &format!("run_jj: jj {args_str}"));
    let output = std::process::Command::new("jj")
        .args(args)
        .output()
        .map_err(|e| format!("failed to run jj: {e}"))?;
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    if !stdout.is_empty() {
        log_msg(log, &format!("run_jj: stdout: {stdout}"));
    }
    if !stderr.is_empty() {
        log_msg(log, &format!("run_jj: stderr: {stderr}"));
    }
    if !output.status.success() {
        return Err(format!("jj {args_str} failed (exit {}): {stderr}", output.status).into());
    }
    Ok(())
}

fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
    log_msg(&opts.log, &format!("finalize_exec: starting opts={opts:?}"));

    // Sleep to let trailing writes settle
    let delay = std::time::Duration::from_secs_f64(opts.delay_secs);
    log_msg(&opts.log, &format!("finalize_exec: sleeping {delay:?}"));
    std::thread::sleep(delay);

    // Squash source into target
    let repo_str = opts.repo.to_string_lossy();
    run_jj(
        &[
            "squash",
            "--ignore-immutable",
            "--use-destination-message",
            "--from",
            &opts.source,
            "--into",
            &opts.target,
            "-R",
            &repo_str,
        ],
        &opts.log,
    )?;

    // Advance bookmark to target
    run_jj(
        &[
            "bookmark",
            "set",
            &opts.bookmark,
            "-r",
            &opts.target,
            "-R",
            &repo_str,
        ],
        &opts.log,
    )?;

    if opts.push {
        run_jj(
            &["git", "push", "--bookmark", &opts.bookmark, "-R", &repo_str],
            &opts.log,
        )?;
    }

    log_msg(&opts.log, "finalize_exec: done");
    Ok(())
}

pub fn build_exec_args(opts: &FinalizeOpts) -> Vec<String> {
    let mut args = vec![
        "finalize".to_string(),
        "--exec".to_string(),
        "--repo".to_string(),
        opts.repo.to_string_lossy().to_string(),
        "--source".to_string(),
        opts.source.clone(),
        "--target".to_string(),
        opts.target.clone(),
        "--bookmark".to_string(),
        opts.bookmark.clone(),
        "--delay".to_string(),
        opts.delay_secs.to_string(),
        "--log".to_string(),
        opts.log.to_string_lossy().to_string(),
    ];
    if opts.push {
        args.push("--push".to_string());
    }
    args
}

/// Spawn a detached child process with `--exec` and return immediately.
/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
/// it to `finalize_exec()` where the actual work happens.
fn detach(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
    log_msg(&opts.log, &format!("detach: parent starting opts={opts:?}"));

    let exe = std::env::current_exe()?;
    let args = build_exec_args(opts);
    log_msg(&opts.log, &format!("detach: exe={exe:?} args={args:?}"));

    let mut cmd = std::process::Command::new(exe);
    cmd.args(&args).stdin(Stdio::null());

    #[cfg(unix)]
    {
        use std::os::unix::process::CommandExt;
        unsafe {
            cmd.pre_exec(|| {
                libc::setsid();
                Ok(())
            });
        }
    }

    let child = cmd.spawn()?;
    log_msg(
        &opts.log,
        &format!("detach: spawned child pid={}", child.id()),
    );
    eprintln!(
        "finalize: detached (pid {}), log: {}",
        child.id(),
        opts.log.display()
    );
    Ok(())
}

pub fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
    log_msg(&opts.log, &format!("finalize: entry opts={opts:?}"));
    let result = if opts.detach && !opts.exec {
        detach(opts)
    } else {
        finalize_exec(opts)
    };
    match &result {
        Ok(()) => log_msg(&opts.log, "finalize: exit ok"),
        Err(e) => log_msg(&opts.log, &format!("finalize: exit err={e}")),
    }
    result
}

#[cfg(test)]
mod tests {
    use std::path::PathBuf;

    use super::*;
    use crate::{Cli, Commands};
    use clap::Parser;

    fn parse(args: &[&str]) -> FinalizeArgs {
