        assert_eq!(args.repo, PathBuf::from("."));
        assert_eq!(args.source, "@");
        assert_eq!(args.target, "@-");
        assert_eq!(args.bookmark, "main");
        assert_eq!(args.delay, 10.0);
        assert!(!args.push);
        assert!(!args.detach);
    }

    #[test]
