        assert!(args.dir.is_none());
        assert!(!args.private);
        assert!(!args.dry_run);
    }

    #[test]
    fn all_opts() {
        let args = parse(&[
            "vc-x1",
            "new",
            "my-project",
            "--owner",
            "myorg",
            "--dir",
            "/tmp/projects",
            "--private",
            "--dry-run",
