        plan.symlink_path.display(),
        plan.abs_target.display()
    );

    eprintln!("\nDone! Project created at {}", project_dir.display());
    eprintln!("  Code repo:    {code_repo}");
    eprintln!("  Session repo: {session_repo}");

    Ok(())
}

